/* Test driver */
public class Main {
    public static void main(String[] args) {
        StateMachine sm = new StateMachineBuilder("Order")
                .initialState("NEW").state("PAID").state("DONE")
                .transition("NEW", "PAY", "PAID")
                .transition("PAID", "SHIP", "DONE")
                .build();
        sm.fire("PAY");
        sm.fire("SHIP");
        System.out.println(sm.getCurrentStateName().equals("DONE") ? "FLOW_OK" : "FLOW_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        StateMachine sm = new StateMachineBuilder("M")
                .initialState("A").state("B")
                .transition("A", "GO", "B")
                .build();
        boolean ok = sm.fire("NOPE");
        System.out.println(!ok && sm.getCurrentStateName().equals("A") ? "INVALID_OK" : "INVALID_FAIL");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        StateMachine sm = new StateMachineBuilder("L")
                .initialState("RED").state("GREEN")
                .onEntry("GREEN", new Action() { public void execute(Event e) { System.out.println("ENTRY_GREEN"); } public String getDescription() { return ""; } })
                .transition("RED", "GO", "GREEN")
                .build();
        sm.fire("GO");
        System.out.println(sm.getCurrentStateName().equals("GREEN") ? "STATE_OK" : "STATE_FAIL");
    }
}
